/**
 * Валидация SEO пропсов
 * Выводит предупреждения в консоль при превышении рекомендуемых лимитов
 */
function validateSEOProps({ title, description }) {
    if (process.env.NODE_ENV === 'production') {
        return;
    }
    const TITLE_MAX_LENGTH = 60;
    const DESCRIPTION_MAX_LENGTH = 160;
    if (title.length > TITLE_MAX_LENGTH) {
        console.warn(`[SEOHead] Title превышает рекомендуемую длину (${title.length} > ${TITLE_MAX_LENGTH} символов). ` +
            'Рекомендуется сократить до 60 символов для лучшего отображения в поиске.');
    }
    if (description.length > DESCRIPTION_MAX_LENGTH) {
        console.warn(`[SEOHead] Description превышает рекомендуемую длину (${description.length} > ${DESCRIPTION_MAX_LENGTH} символов). ` +
            'Рекомендуется сократить до 160 символов для лучшего отображения в поиске.');
    }
    // Проверка на пустые значения
    if (!title.trim()) {
        console.error('[SEOHead] Title не может быть пустым.');
    }
    if (!description.trim()) {
        console.error('[SEOHead] Description не может быть пустым.');
    }
}

export { validateSEOProps };
